+	ac.mu.Lock()
+	if ac.codexThrottle != nil {
+		ac.codexThrottle.RecordRateLimit(paneID, waitSeconds)
+	}
+	ac.mu.Unlock()
+
+	// Also trigger the existing cap cooldown mechanism
